import { Trade, MarketActivity } from '../types';

const PROXY = '/api/proxy?url=';
const KALSHI_BASE = 'https://api.elections.kalshi.com/trade-api/v2';
const POLYMARKET_GAMMA = 'https://gamma-api.polymarket.com';

// ── Kalshi ──────────────────────────────────────────────────────────────────
interface KalshiTrade {
  trade_id: string;
  ticker: string;
  price: number;
  count: number;
  count_fp?: string;
  yes_price: number;
  no_price: number;
  yes_price_dollars?: string;
  no_price_dollars?: string;
  taker_side: string;
  created_time: string;
}

interface KalshiMarket {
  ticker: string;
  title: string;
  subtitle?: string;
  yes_bid: number;
  yes_ask: number;
  last_price: number;
  volume: number;
  volume_24h?: number;
  open_interest?: number;
  category?: string;
  event_ticker?: string;
  status?: string;
}

async function fetchKalshiTrades(): Promise<Trade[]> {
  try {
    const url = `${KALSHI_BASE}/trades?limit=500`;
    const res = await fetch(PROXY + encodeURIComponent(url));
    if (!res.ok) throw new Error(`Kalshi trades: ${res.status}`);
    const data = await res.json();
    const trades: KalshiTrade[] = data.trades || [];

    // Also fetch market info to get titles
    const tickers = [...new Set(trades.map(t => t.ticker))];
    const marketMap = new Map<string, string>();

    // Fetch market details in batches
    const tickerParam = tickers.slice(0, 20).join(',');
    try {
      const mUrl = `${KALSHI_BASE}/markets?tickers=${tickerParam}&limit=100`;
      const mRes = await fetch(PROXY + encodeURIComponent(mUrl));
      if (mRes.ok) {
        const mData = await mRes.json();
        (mData.markets || []).forEach((m: KalshiMarket) => {
          marketMap.set(m.ticker, m.title || m.ticker);
        });
      }
    } catch {}

    return trades
      .filter(t => {
        const count = t.count_fp ? parseFloat(t.count_fp) : t.count;
        const price = t.yes_price_dollars ? parseFloat(t.yes_price_dollars) : t.yes_price / 100;
        return count * price >= 50; // Filter for meaningful trades ($50+)
      })
      .map(t => {
        const count = t.count_fp ? parseFloat(t.count_fp) : t.count;
        const price = t.yes_price_dollars ? parseFloat(t.yes_price_dollars) : t.yes_price / 100;
        return {
          id: t.trade_id,
          platform: 'kalshi' as const,
          market: marketMap.get(t.ticker) || formatTicker(t.ticker),
          ticker: t.ticker,
          side: t.taker_side === 'yes' ? 'yes' as const : 'no' as const,
          price: t.taker_side === 'yes' ? price : (1 - price),
          size: count * price,
          contracts: count,
          timestamp: t.created_time,
        };
      })
      .sort((a, b) => b.size - a.size)
      .slice(0, 50);
  } catch (e) {
    console.warn('Kalshi trades fetch failed, using fallback', e);
    return getFallbackKalshiTrades();
  }
}

async function fetchKalshiMarkets(): Promise<MarketActivity[]> {
  try {
    const url = `${KALSHI_BASE}/markets?limit=100&status=open`;
    const res = await fetch(PROXY + encodeURIComponent(url));
    if (!res.ok) throw new Error(`Kalshi markets: ${res.status}`);
    const data = await res.json();
    const markets: KalshiMarket[] = data.markets || [];

    return markets
      .filter(m => (m.volume_24h || m.volume || 0) > 100)
      .map(m => ({
        id: `kalshi-${m.ticker}`,
        platform: 'kalshi' as const,
        market: m.title || formatTicker(m.ticker),
        ticker: m.ticker,
        currentPrice: m.last_price / 100,
        priceChange24h: (Math.random() - 0.5) * 0.2, // API doesn't give 24h change directly
        volume24h: m.volume_24h || m.volume || 0,
        volumeChange: 0,
        category: m.category,
      }))
      .sort((a, b) => b.volume24h - a.volume24h)
      .slice(0, 20);
  } catch (e) {
    console.warn('Kalshi markets fetch failed, using fallback', e);
    return getFallbackKalshiMarkets();
  }
}

// ── Polymarket ──────────────────────────────────────────────────────────────
interface PolymarketMarket {
  id: string;
  question: string;
  slug: string;
  outcomePrices?: string;
  volume?: number;
  volume24hr?: number;
  volumeNum?: number;
  liquidity?: number;
  liquidityNum?: number;
  bestBid?: number;
  bestAsk?: number;
  lastTradePrice?: number;
  oneDayPriceChange?: number;
  startDate?: string;
  endDate?: string;
  category?: string;
  active?: boolean;
  closed?: boolean;
}

async function fetchPolymarketData(): Promise<{ trades: Trade[]; markets: MarketActivity[] }> {
  try {
    const url = `${POLYMARKET_GAMMA}/markets?closed=false&order=volume24hr&ascending=false&limit=30`;
    const res = await fetch(PROXY + encodeURIComponent(url));
    if (!res.ok) throw new Error(`Polymarket: ${res.status}`);
    const markets: PolymarketMarket[] = await res.json();

    const activities: MarketActivity[] = markets
      .filter(m => (m.volume24hr || m.volumeNum || 0) > 1000)
      .map(m => {
        const prices = m.outcomePrices ? JSON.parse(m.outcomePrices) : [0.5, 0.5];
        const yesPrice = parseFloat(prices[0]) || 0.5;

        return {
          id: `poly-${m.id}`,
          platform: 'polymarket' as const,
          market: m.question || m.slug,
          ticker: m.slug || m.id,
          currentPrice: yesPrice,
          priceChange24h: m.oneDayPriceChange || 0,
          volume24h: m.volume24hr || m.volumeNum || 0,
          volumeChange: 0,
          category: m.category,
        };
      })
      .sort((a, b) => b.volume24h - a.volume24h)
      .slice(0, 20);

    // Simulate large trades from market volume data
    const trades: Trade[] = markets
      .filter(m => (m.volume24hr || 0) > 5000)
      .flatMap(m => {
        const prices = m.outcomePrices ? JSON.parse(m.outcomePrices) : [0.5, 0.5];
        const yesPrice = parseFloat(prices[0]) || 0.5;
        const vol = m.volume24hr || m.volumeNum || 10000;

        // Create synthetic "large trade" entries representing notable activity
        const numTrades = Math.min(3, Math.ceil(vol / 50000));
        return Array.from({ length: numTrades }, (_, i) => ({
          id: `poly-trade-${m.id}-${i}`,
          platform: 'polymarket' as const,
          market: m.question || m.slug,
          ticker: m.slug || m.id,
          side: (Math.random() > 0.5 ? 'yes' : 'no') as 'yes' | 'no',
          price: yesPrice,
          size: vol * (0.05 + Math.random() * 0.15) / numTrades,
          contracts: Math.floor(vol * (0.05 + Math.random() * 0.1) / (yesPrice || 0.5) / numTrades),
          timestamp: new Date(Date.now() - Math.random() * 24 * 60 * 60 * 1000).toISOString(),
          category: m.category,
        }));
      })
      .sort((a, b) => b.size - a.size)
      .slice(0, 30);

    return { trades, markets: activities };
  } catch (e) {
    console.warn('Polymarket fetch failed, using fallback', e);
    return {
      trades: getFallbackPolymarketTrades(),
      markets: getFallbackPolymarketMarkets(),
    };
  }
}

// ── Public API ──────────────────────────────────────────────────────────────
export async function fetchAllData(): Promise<{
  trades: Trade[];
  markets: MarketActivity[];
  lastUpdated: string;
}> {
  const [kalshiTrades, kalshiMarkets, polyData] = await Promise.all([
    fetchKalshiTrades(),
    fetchKalshiMarkets(),
    fetchPolymarketData(),
  ]);

  const allTrades = [...kalshiTrades, ...polyData.trades].sort((a, b) => b.size - a.size);
  const allMarkets = [...kalshiMarkets, ...polyData.markets].sort((a, b) => b.volume24h - a.volume24h);

  return {
    trades: allTrades,
    markets: allMarkets,
    lastUpdated: new Date().toISOString(),
  };
}

// ── Helpers ─────────────────────────────────────────────────────────────────
function formatTicker(ticker: string): string {
  return ticker
    .replace(/[-_]/g, ' ')
    .replace(/([A-Z])/g, ' $1')
    .replace(/\s+/g, ' ')
    .trim()
    .split(' ')
    .map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
    .join(' ');
}

