import { useState, useEffect, useCallback } from 'react';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Skeleton } from '@/components/ui/skeleton';
import { RefreshCw, AlertCircle, Zap } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';

import { Trade, MarketActivity, FilterPlatform } from './types';
import { fetchAllData } from './lib/api';
import TradeRow from './components/TradeRow';
import MarketRow from './components/MarketRow';
import SummaryBar from './components/SummaryBar';

export default function App() {
  const [trades, setTrades] = useState<Trade[]>([]);
  const [markets, setMarkets] = useState<MarketActivity[]>([]);
  const [platform, setPlatform] = useState<FilterPlatform>('all');
  const [view, setView] = useState<'trades' | 'movers'>('trades');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<string | null>(null);
  const [refreshing, setRefreshing] = useState(false);

  const loadData = useCallback(async (isRefresh = false) => {
    if (isRefresh) setRefreshing(true);
    else setLoading(true);
    setError(null);
    try {
      const data = await fetchAllData();
      setTrades(data.trades);
      setMarkets(data.markets);
      setLastUpdated(data.lastUpdated);
    } catch (e) {
      setError('Failed to load data');
      console.error(e);
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    loadData();
    const interval = setInterval(() => loadData(true), 60_000);
    return () => clearInterval(interval);
  }, [loadData]);

  const filteredTrades = platform === 'all'
    ? trades
    : trades.filter(t => t.platform === platform);

  const filteredMarkets = platform === 'all'
    ? markets
    : markets.filter(m => m.platform === platform);

  const kalshiCount = trades.filter(t => t.platform === 'kalshi').length;
  const polyCount = trades.filter(t => t.platform === 'polymarket').length;

  return (
    <div className="w-full h-full overflow-hidden flex flex-col bg-zinc-950">
      {/* Header */}
      <div className="flex-shrink-0 px-3 pt-3 pb-2 space-y-2">
        {/* Status bar */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Zap size={12} className="text-amber-400" />
            <span className="text-[10px] text-zinc-500 uppercase tracking-wider">
              Live • {kalshiCount + polyCount} notable trades
            </span>
          </div>
          <div className="flex items-center gap-2">
            {lastUpdated && (
              <span className="text-[10px] text-zinc-600">
                {formatDistanceToNow(new Date(lastUpdated), { addSuffix: true })}
              </span>
            )}
            <button
              onClick={() => loadData(true)}
              disabled={refreshing}
              className="p-1 text-zinc-500 hover:text-zinc-300 transition-colors disabled:opacity-50"
            >
              <RefreshCw size={12} className={refreshing ? 'animate-spin' : ''} />
            </button>
          </div>
        </div>

        {/* Summary stats */}
        {!loading && <SummaryBar trades={filteredTrades} markets={filteredMarkets} />}

        {/* View + Platform filters */}
        <div className="flex items-center gap-2">
          {/* View toggle */}
          <div className="flex bg-zinc-900 border border-zinc-800">
            <button
              onClick={() => setView('trades')}
              className={`px-2.5 py-1 text-[11px] font-medium transition-colors ${
                view === 'trades'
                  ? 'bg-zinc-800 text-zinc-100'
                  : 'text-zinc-500 hover:text-zinc-300'
              }`}
            >
              Large Bets
            </button>
            <button
              onClick={() => setView('movers')}
              className={`px-2.5 py-1 text-[11px] font-medium transition-colors ${
                view === 'movers'
                  ? 'bg-zinc-800 text-zinc-100'
                  : 'text-zinc-500 hover:text-zinc-300'
              }`}
            >
              Notable Movers
            </button>
          </div>

          <div className="flex-1" />

          {/* Platform filter */}
          <div className="flex gap-1">
            {(['all', 'kalshi', 'polymarket'] as FilterPlatform[]).map((p) => (
              <button
                key={p}
                onClick={() => setPlatform(p)}
                className={`px-2 py-0.5 text-[10px] font-semibold uppercase tracking-wider border transition-colors ${
                  platform === p
                    ? p === 'kalshi'
                      ? 'border-blue-500/50 text-blue-400 bg-blue-500/15'
                      : p === 'polymarket'
                      ? 'border-purple-500/50 text-purple-400 bg-purple-500/15'
                      : 'border-zinc-600 text-zinc-200 bg-zinc-800'
                    : 'border-zinc-800 text-zinc-600 hover:text-zinc-400'
                }`}
              >
                {p === 'all' ? 'All' : p === 'kalshi' ? 'Kalshi' : 'Polymarket'}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Error */}
      {error && (
        <div className="mx-3 mb-2 flex items-center gap-2 bg-red-500/10 border border-red-500/30 px-3 py-2">
          <AlertCircle size={12} className="text-red-400" />
          <span className="text-xs text-red-400">{error}</span>
        </div>
      )}

      {/* Content */}
      <div className="flex-1 min-h-0">
        {loading ? (
          <div className="px-3 space-y-2 pt-2">
            {Array.from({ length: 8 }).map((_, i) => (
              <div key={i} className="flex items-center gap-3 py-2">
                <Skeleton className="h-4 w-8" />
                <div className="flex-1 space-y-1">
                  <Skeleton className="h-3 w-full" />
                  <Skeleton className="h-2.5 w-2/3" />
                </div>
                <Skeleton className="h-4 w-12" />
              </div>
            ))}
          </div>
        ) : (
          <ScrollArea className="h-full">
            {view === 'trades' ? (
              filteredTrades.length > 0 ? (
                <div>
                  {filteredTrades.map((trade) => (
                    <TradeRow key={trade.id} trade={trade} />
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-12 text-zinc-500">
                  <AlertCircle size={20} className="mb-2" />
                  <span className="text-xs">No large bets found</span>
                </div>
              )
            ) : (
              filteredMarkets.length > 0 ? (
                <div>
                  {filteredMarkets.map((market) => (
                    <MarketRow key={market.id} market={market} />
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-12 text-zinc-500">
                  <AlertCircle size={20} className="mb-2" />
                  <span className="text-xs">No notable movers found</span>
                </div>
              )
            )}
          </ScrollArea>
        )}
      </div>

      {/* Footer */}
      <div className="flex-shrink-0 px-3 py-1.5 border-t border-zinc-800/60 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="flex items-center gap-1">
            <div className="w-1.5 h-1.5 bg-blue-400 rounded-full" />
            <span className="text-[10px] text-zinc-500">Kalshi ({kalshiCount})</span>
          </div>
          <div className="flex items-center gap-1">
            <div className="w-1.5 h-1.5 bg-purple-400 rounded-full" />
            <span className="text-[10px] text-zinc-500">Polymarket ({polyCount})</span>
          </div>
        </div>
        <span className="text-[10px] text-zinc-600">
          Sorted by size • Auto-refresh 60s
        </span>
      </div>
    </div>
  );
}
